package ui.student;
import javax.swing.*;import javax.swing.table.*;import java.awt.*;import controller.*;import dao.*;import model.*;import util.*;import ui.common.TableStyle;
public class MyApplicationsPanel extends JPanel{ JTable table=new JTable(); public MyApplicationsPanel(){ setBackground(UITheme.BG); setLayout(new BorderLayout()); add(UITheme.title("My Applications"),BorderLayout.NORTH); TableStyle.apply(table); add(new JScrollPane(table),BorderLayout.CENTER); load(); } void load(){ Student s=new StudentDAO().getByUserId(Session.getUserId()); DefaultTableModel m=new DefaultTableModel(new Object[]{"Application ID","Internship ID","Status","Applied At"},0); if(s!=null) for(Application a:new ApplicationController().byStudent(s.getId())) m.addRow(new Object[]{a.getId(),a.getJobId(),a.getStatus(),a.getAppliedAt()}); table.setModel(m); TableStyle.apply(table);} }
